-- Table unifiée pour tous les lieux "En Famille"
CREATE TABLE IF NOT EXISTS public.family_venues (
  id SERIAL PRIMARY KEY,
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  category TEXT NOT NULL,       -- 'Parc d''attractions', 'Aire de jeux', 'Cinema', etc.
  groupe TEXT DEFAULT '',       -- sous-groupe pour affichage (ex: 'Multiplexes & grands cinemas')
  description TEXT DEFAULT '',
  adresse TEXT DEFAULT '',
  ville TEXT DEFAULT 'Toulouse',
  horaires TEXT DEFAULT '',
  tarif TEXT DEFAULT '',
  telephone TEXT DEFAULT '',
  latitude DOUBLE PRECISION,
  longitude DOUBLE PRECISION,
  website_url TEXT DEFAULT '',
  ticket_url TEXT DEFAULT '',
  lien_maps TEXT DEFAULT '',
  photo TEXT DEFAULT '',
  is_active BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.family_venues ENABLE ROW LEVEL SECURITY;
CREATE POLICY "anon read family_venues" ON public.family_venues FOR SELECT USING (true);

